def find_triangles_with_t(data):
    G = nx.Graph(line.split("-") for line in data)
    cliques = list(nx.find_cliques(G))

    conn = set()
    for clique in cliques:
        for a, b, c in combinations(clique, 3):
            if (
                    "t" in (a[0], b[0], c[0])
                    and (a, b) in G.edges()
                    and (b, c) in G.edges()
                    and (c, a) in G.edges()
            ):
                conn.add(tuple(sorted((a, b, c))))

    return len(conn)


