from itertools import combinations


def bron_kerbosch(
    R: set[str],
    P: set[str],
    X: set[str],
    graph: dict[str, set[str]],
    cliques: list[set[str]],
):
    """
    Uses the Bron-Kerbosch algorithm to find all maximal cliques in a graph.

    Args:
        R: A set of vertices in the current clique.
        P: A set of vertices that can be added to the current clique.
        X: A set of vertices that cannot be added to the current clique.
        graph: A dictionary of vertices and their neighbors.
        cliques: A list to store

    Reference: https://en.wikipedia.org/wiki/Bron%E2%80%93Kerbosch_algorithm
    """

    if not P and not X:
        cliques.append(R)
        return

    u = next(iter(P | X))
    for v in P - graph[u]:
        bron_kerbosch(R | {v}, P & graph[v], X & graph[v], graph, cliques)
        P.remove(v)
        X.add(v)


def part_1() -> int:
    connections = {}
    for line in open('year_2024_day_23.txt').read().splitlines():
        a, b = line.split("-")
        connections[a] = connections.get(a, set()) | {b}
        connections[b] = connections.get(b, set()) | {a}

    cliques = []
    bron_kerbosch(set(), set(connections.keys()), set(), connections, cliques)

    # fixes order of vertices in cliques, python sets are unordered
    cliques = [sorted(clique) for clique in cliques]

    candidates = set()
    for clique in cliques:
        if len(clique) >= 3:
            for comb in combinations(clique, 3):
                if any(vertex.startswith("t") for vertex in comb):
                    candidates.add(tuple(comb))

    return len(candidates)


def part_2() -> str:
    connections = {}
    for line in open('year_2024_day_23.txt').read().splitlines():
        a, b = line.split("-")
        connections[a] = connections.get(a, set()) | {b}
        connections[b] = connections.get(b, set()) | {a}

    cliques = []
    bron_kerbosch(set(), set(connections.keys()), set(), connections, cliques)
    largest_clique = max(cliques, key=len)

    return ",".join(sorted(largest_clique))

from typing import Any

Grid = list[list[str]]
Position = tuple[int, int]
Region = set[Position]

DIRECTIONS = [(0, 1), (1, 0), (0, -1), (-1, 0)]


def is_valid(grid: Grid, row: int, col: int):
    return 0 <= row < len(grid) and 0 <= col < len(grid[0])


def find_region(
    grid: Grid,
    area: str,
    row: int,
    col: int,
    seen: set[Position],
) -> Region:
    if not is_valid(grid, row, col):
        return set()

    if grid[row][col] != area:
        return set()

    if (row, col) in seen:
        return set()

    seen.add((row, col))

    result = {(row, col)}

    for dx, dy in DIRECTIONS:
        new_row = row + dx
        new_col = col + dy

        if is_valid(grid, new_row, new_col) and (new_row, new_col) not in seen:
            result.update(find_region(grid, area, new_row, new_col, seen))

    return result


def find_all_regions(grid: Grid) -> list[Region]:
    seen = set()
    regions = []

    for row in range(len(grid)):
        for col in range(len(grid[0])):
            if (row, col) not in seen:
                region = find_region(grid, grid[row][col], row, col, set())

                seen.update(region)
                regions.append(region)

    return regions


def part_1() -> Any:
    grid: Grid = [list(x) for x in open('year_2024_day_12.txt').read().splitlines()]
    regions = find_all_regions(grid)

    result = 0

    for region in regions:
        area = len(region)
        perimeter = 0

        for row, col in region:
            for dx, dy in DIRECTIONS:
                new_row = row + dx
                new_col = col + dy

                if (new_row, new_col) not in region:
                    perimeter += 1

        result += area * perimeter

    return result


def part_2() -> Any:
    grid: Grid = [list(x) for x in open('year_2024_day_12.txt').read().splitlines()]
    regions = find_all_regions(grid)

    result = 0

    for region in regions:
        area = len(region)

        seen = set()
        corners = 0

        for row, col in region:
            for dx, dy in [
                (-0.5, -0.5),
                (0.5, -0.5),
                (0.5, 0.5),
                (-0.5, 0.5),
            ]:
                new_row = row + dx
                new_col = col + dy

                if (new_row, new_col) in seen:
                    continue

                seen.add((new_row, new_col))

                adjacent = sum(
                    (new_row + r, new_col + c) in region
                    for r, c in [
                        (-0.5, -0.5),
                        (0.5, -0.5),
                        (0.5, 0.5),
                        (-0.5, 0.5),
                    ]
                )

                if adjacent == 1 or adjacent == 3:
                    corners += 1
                elif adjacent == 2:
                    # diagonal
                    pattern = [
                        (r, c) in region
                        for r, c in [
                            (new_row - 0.5, new_col - 0.5),
                            (new_row + 0.5, new_col + 0.5),
                        ]
                    ]

                    if pattern == [True, True] or pattern == [False, False]:
                        corners += 2

        result += area * corners

    return result

