def quadrant_position(rows: int, cols: int, row: int, col: int) -> int:
    mid_row = rows // 2
    mid_col = cols // 2

    if (rows % 2 == 1 and row == mid_row) or (cols % 2 == 1 and col == mid_col):
        return -1

    if row < mid_row:
        if col < mid_col:
            return 0
        else:
            return 1
    else:
        if col < mid_col:
            return 2
        else:
            return 3


def part_1() -> int:
    robots = get_robots()

    rows = 103
    cols = 101

    for i, (row, col, row_v, col_v) in enumerate(robots):
        robots[i] = (
            (row + row_v * 100) % rows,
            (col + col_v * 100) % cols,
            row_v,
            col_v,
        )

    quadrants = {}

    for robot in robots:
        pos = quadrant_position(rows, cols, robot[0], robot[1])
        quadrants[pos] = quadrants.get(pos, 0) + 1

    result = 1

    for key, count in quadrants.items():
        if key != -1:
            result *= count

    return result


