from enum import Enum
from heapq import heappop, heappush

Grid = list[list[str]]
Position = tuple[int, int]


class Face(Enum):
    NORTH = 0
    EAST = 1
    SOUTH = 2
    WEST = 3

    def counterclockwise(self):
        return Face((self.value - 1) % 4)

    def clockwise(self):
        return Face((self.value + 1) % 4)

    def __lt__(self, other):
        return self.value < other.value


DIRECTION = {
    Face.NORTH: (-1, 0),
    Face.EAST: (0, 1),
    Face.SOUTH: (1, 0),
    Face.WEST: (0, -1),
}


def find_point(grid: Grid, type: str) -> Position:
    for row in range(len(grid)):
        for col in range(len(grid[0])):
            if grid[row][col] == type:
                return row, col

    raise ValueError(f"Can't find point {type}")


def part_1(file: str = "input.txt") -> int:
    grid = [list(line) for line in open('year_2024_day_16.txt').read().splitlines()]
    start_row, start_col = find_point(grid, "S")
    end_row, end_col = find_point(grid, "E")

    pq = [(0, start_row, start_col, Face.EAST)]

    seen: dict[tuple[*Position, Face], float] = {}

    while pq:
        score, r, c, facing = heappop(pq)

        if score >= seen.get((r, c, facing), float("inf")):
            continue

        seen[(r, c, facing)] = score

        if (r, c) == (end_row, end_col):
            return score

        dr, dc = DIRECTION[facing]
        new_r, new_c = r + dr, c + dc
        if (
            0 <= new_r < len(grid)
            and 0 <= new_c < len(grid[0])
            and grid[new_r][new_c] != "#"
        ):
            heappush(pq, (score + 1, new_r, new_c, facing))

        for new_facing in (facing.clockwise(), facing.counterclockwise()):
            heappush(pq, (score + 1000, r, c, new_facing))

    return -1


def part_2(file: str = "input.txt") -> int:
    grid = [list(line) for line in open('year_2024_day_16.txt').read().splitlines()]
    start_row, start_col = find_point(grid, "S")
    end_row, end_col = find_point(grid, "E")

    min_score = part_1(file)

    queue = deque([(0, start_row, start_col, Face.EAST, {(start_row, start_col)})])

    seen: dict[tuple[*Position, Face], float] = {}
    tiles: set[Position] = set({(start_row, start_col)})

    while queue:
        score, r, c, facing, path = queue.popleft()

        if score > min_score:
            continue

        if (r, c) == (end_row, end_col):
            tiles.update(path | {(r, c)})
            continue

        if seen.get((r, c, facing), float("inf")) < score:
            continue

        seen[(r, c, facing)] = score

        dr, dc = DIRECTION[facing]
        new_r, new_c = r + dr, c + dc
        if (
            0 <= new_r < len(grid)
            and 0 <= new_c < len(grid[0])
            and grid[new_r][new_c] != "#"
            and (new_r, new_c) not in path
        ):
            queue.append((score + 1, new_r, new_c, facing, path | {(new_r, new_c)}))

        for new_facing in (facing.clockwise(), facing.counterclockwise()):
            queue.append((score + 1000, r, c, new_facing, path))

    return len(tiles)

from typing import Any

Grid = list[list[int]]


def is_valid(grid: Grid, row: int, col: int):
    return 0 <= row < len(grid) and 0 <= col < len(grid[0])


def dfs(
    grid: Grid,
    row: int,
    col: int,
    trail: list[tuple[int, int]],
    heads: dict[tuple[int, int], int],
    seen: set[tuple[int, int]] | None = None,
) -> None:
    current = grid[row][col]
    upcoming = current + 1

    if current == 9:
        if seen is None or (row, col) not in seen:
            heads[trail[0]] = heads.get(trail[0], 0) + 1

            if seen is not None:
                seen.add((row, col))

        return

    for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
        if not is_valid(grid, row + dr, col + dc):
            continue

        if grid[row + dr][col + dc] == upcoming:
            trail.append((row + dr, col + dc))
            dfs(grid, row + dr, col + dc, trail, heads, seen)
            trail.pop()


def solve(track_seen: bool = True) -> int:
    grid: Grid = [
        [int(char) for char in line] for line in open('year_2024_day_10.txt').read().splitlines()
    ]

    trailheads = [
        (row, col)
        for row in range(len(grid))
        for col in range(len(grid[0]))
        if grid[row][col] == 0
    ]

    heads = {pos: 0 for pos in trailheads}
    seen = set() if track_seen else None

    for row, col in trailheads:
        dfs(grid, row, col, [], heads, seen)

    return sum(heads.values())


def part_1() -> Any:
    return solve()


def part_2() -> Any:
    return solve(track_seen=False)

from typing import Generator

Grid = list[list[str]]
Position = tuple[int, int]

DIRECTIONS = {
    "<": (0, -1),
    ">": (0, 1),
    "^": (-1, 0),
    "v": (1, 0),
}


def find_robot(grid: Grid) -> Position:
    for row in range(len(grid)):
        for col in range(len(grid[0])):
            if grid[row][col] == "@":
                return row, col

    raise ValueError("No robot found")


def find_box(grid: Grid) -> Generator[Position, None, None]:
    for row in range(len(grid)):
        for col in range(len(grid[0])):
            if grid[row][col] in ["O", "["]:
                yield row, col


def is_valid(grid: Grid, row: int, col: int) -> bool:
    return 0 <= row < len(grid) and 0 <= col < len(grid[0]) and grid[row][col] != "#"


def check_movable(grid: Grid, row: int, col: int, dr: int, dc: int, seen: set) -> bool:
    if (row, col) in seen:
        return True
    seen.add((row, col))

    nr, nc = row + dr, col + dc
    match grid[nr][nc]:
        case "#":
            return False
        case "[":
            return check_movable(grid, nr, nc, dr, dc, seen) and check_movable(
                grid, nr, nc + 1, dr, dc, seen
            )
        case "]":
            return check_movable(grid, nr, nc, dr, dc, seen) and check_movable(
                grid, nr, nc - 1, dr, dc, seen
            )
        case "O":
            return check_movable(grid, nr, nc, dr, dc, seen)
    return True


def process_instruction(grid: Grid, row: int, col: int, instruction: str) -> Position:
    dr, dc = DIRECTIONS[instruction]

    nr, nc = row + dr, col + dc

    if not is_valid(grid, nr, nc):
        return row, col

    if grid[nr][nc] in ["[", "]", "O"]:
        seen = set()

        if not check_movable(grid, row, col, dr, dc, seen):
            return row, col

        while len(seen) > 0:
            for r, c in seen.copy():
                nr2, nc2 = r + dr, c + dc
                if (nr2, nc2) not in seen:
                    if grid[nr2][nc2] != "@" and grid[r][c] != "@":
                        grid[nr2][nc2] = grid[r][c]
                        grid[r][c] = "."

                    seen.remove((r, c))

        grid[row][col], grid[nr][nc] = grid[nr][nc], grid[row][col]
        return nr, nc

    grid[row][col], grid[nr][nc] = grid[nr][nc], grid[row][col]
    return nr, nc


def gps(grid: Grid) -> int:
    return sum(100 * box[0] + box[1] for box in find_box(grid))


def part_1() -> int:
    file = open('year_2024_day_15.txt', "r").read()
    grid = [[char for char in line] for line in file.split("\n\n")[0].split("\n")]
    instructions = "".join(file.split("\n\n")[1].strip().split("\n"))

    row, col = find_robot(grid)
    for instruction in instructions:
        row, col = process_instruction(grid, row, col, instruction)

    return gps(grid)


def part_2() -> int:
    file = open('year_2024_day_15.txt', "r").read()
    initial_grid = [
        [char for char in line] for line in file.split("\n\n")[0].split("\n")
    ]
    grid = []

    instructions = "".join(file.split("\n\n")[1].strip().split("\n"))

    # expand the grid
    for row in range(len(initial_grid)):
        if len(grid) <= row or row not in grid:
            grid.append([])

        for col in range(len(initial_grid[0])):
            match initial_grid[row][col]:
                case "#":
                    grid[row].extend(["#", "#"])
                case "O":
                    grid[row].extend(["[", "]"])
                case ".":
                    grid[row].extend([".", "."])
                case "@":
                    grid[row].extend(["@", "."])

    row, col = find_robot(grid)
    for instruction in instructions:
        row, col = process_instruction(grid, row, col, instruction)

    return gps(grid)

from collections import deque
from typing import Generator

Grid = list[list[str]]
Position = tuple[int, int]
DIRECTIONS = ((-1, 0), (1, 0), (0, -1), (0, 1))


def find_point(grid: Grid, type: str) -> Position:
    return next(find_points(grid, type))


def find_points(grid: Grid, type: str) -> Generator[Position, None, None]:
    for row in range(len(grid)):
        for col in range(len(grid[0])):
            if grid[row][col] == type:
                yield row, col


def calculate_distances(
    grid: Grid,
    start_row: int,
    start_col: int,
    walls: set[Position],
) -> dict[Position, int]:
    distances: dict[Position, int] = {}
    queue = deque([(start_row, start_col, 0)])
    seen = set() | walls

    while queue:
        r, c, dist = queue.popleft()

        distances[(r, c)] = dist

        for dr, dc in DIRECTIONS:
            new_r, new_c = r + dr, c + dc

            if (
                0 <= new_r < len(grid)
                and 0 <= new_c < len(grid[0])
                and (new_r, new_c) not in seen
            ):
                seen.add((r, c))
                queue.append((new_r, new_c, dist + 1))

    return distances


def find_possible_shortcuts(
    grid: Grid,
    distances_from_start: dict[Position, int],
    distances_to_end: dict[Position, int],
    walls: set[Position],
    regular_time: int,
    max_cheat_time: int,
) -> list[int]:
    savings = []
    rows, cols = len(grid), len(grid[0])

    for start_r in range(rows):
        for start_c in range(cols):
            if (start_r, start_c) in walls:
                continue

            for end_r in range(
                max(0, start_r - max_cheat_time),
                min(rows, start_r + max_cheat_time + 1),
            ):
                for end_c in range(
                    max(0, start_c - max_cheat_time),
                    min(cols, start_c + max_cheat_time + 1),
                ):
                    if (end_r, end_c) in walls:
                        continue

                    manhattan_dist = abs(end_r - start_r) + abs(end_c - start_c)
                    if manhattan_dist > max_cheat_time:
                        continue

                    total_time = (
                        distances_from_start[(start_r, start_c)]
                        + manhattan_dist
                        + distances_to_end[(end_r, end_c)]
                    )

                    if total_time < regular_time:
                        savings.append(regular_time - total_time)

    return savings


def find_cheats(
    grid: Grid,
    start_row: int,
    start_col: int,
    end_row: int,
    end_col: int,
    walls: set[Position],
    max_cheat_time: int = 2,
) -> list[int]:
    distances_from_start = calculate_distances(grid, start_row, start_col, walls)
    distances_to_end = calculate_distances(grid, end_row, end_col, walls)

    regular_time = distances_from_start[(end_row, end_col)]

    return find_possible_shortcuts(
        grid,
        distances_from_start,
        distances_to_end,
        walls,
        regular_time,
        max_cheat_time,
    )


def part_1(file: str = "input.txt") -> int:
    grid = [list(line) for line in open('year_2024_day_20.txt').read().splitlines()]
    start_row, start_col = find_point(grid, "S")
    end_row, end_col = find_point(grid, "E")
    walls = set(find_points(grid, "#"))

    savings = find_cheats(grid, start_row, start_col, end_row, end_col, walls)

    return sum(1 for saving in savings if saving >= 100)


def part_2(file: str = "input.txt") -> int:
    grid = [list(line) for line in open('year_2024_day_20.txt').read().splitlines()]
    start_row, start_col = find_point(grid, "S")
    end_row, end_col = find_point(grid, "E")
    walls = set(find_points(grid, "#"))

    savings = find_cheats(
        grid, start_row, start_col, end_row, end_col, walls, max_cheat_time=20
    )

