from collections import defaultdict, deque
from typing import Any


def input():
    with open('year_2024_day_5.txt') as f1:
        content = f1.read()
        splitted = content.split("\n\n")

        rules = {}
        for rule in splitted[0].split("\n"):
            before, after = map(int, rule.split("|"))
            if before not in rules:
                rules[before] = set()

            rules[before].add(after)

        updates = []
        for update in splitted[1].split("\n"):
            if update:
                updates.append([int(x) for x in update.split(',')])

        return rules, updates

def is_valid_order(pages, rules):
    page_positions = {page: i for i, page in enumerate(pages)}

    for before in rules:
        if before in page_positions:
            for after in rules[before]:
                if after in page_positions:
                    if page_positions[before] > page_positions[after]:
                        return False
    return True

def part_1() -> Any:
    rules, updates = input()
    result = 0

    for update in updates:
        if is_valid_order(update, rules):
            middle_idx = len(update) // 2
            result += update[middle_idx]

    return result

def topological_sort(pages, rules):
    """
    Topological sort using Kahn's algorithm

    wiki: https://en.wikipedia.org/wiki/Topological_sorting#Kahn's_algorithm
    """

    adj = defaultdict(set)
    in_degree = {page: 0 for page in pages}

    for before in rules:
        if before in pages:
            for after in rules[before]:
                if after in pages:
                    adj[before].add(after)
                    in_degree[after] += 1

    queue = deque([page for page in pages if in_degree[page] == 0])
    result = []

    while queue:
        page = queue.popleft()
        result.append(page)

        for neighbor in adj[page]:
            in_degree[neighbor] -= 1

            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    return result if len(result) == len(pages) else None

def part_2() -> Any:
    rules, updates = input()
    result = 0

    for update in updates:
        if not is_valid_order(update, rules):
            pages = topological_sort(set(update), rules)

            if pages:
                middle_idx = len(pages) // 2
                result += pages[middle_idx]

    return result

from collections import deque
from typing import TypeAlias

Position: TypeAlias = tuple[int, int]


def solve(rows: int, cols: int, obstructions: list[Position]):
    end_row, end_col = rows - 1, cols - 1

    queue = deque([(0, 0, 0)])  # row, col, distance
    seen = {(0, 0)} | set(obstructions)

    while queue:
        r, c, dist = queue.popleft()

        if (r, c) == (end_row, end_col):
            return dist

        for dr, dc in ((0, 1), (1, 0), (0, -1), (-1, 0)):
            new_r, new_c = r + dr, c + dc
            if 0 <= new_r < rows and 0 <= new_c < cols and (new_r, new_c) not in seen:
                seen.add((new_r, new_c))
                queue.append((new_r, new_c, dist + 1))

    return -1


def part_1() -> int:
    obstructions: list[Position] = [
        Position(map(int, x.split(",")[::-1]))  # row, col
        for x in open('year_2024_day_18.txt').read().splitlines()
    ]

    return solve(71, 71, obstructions[:1024])


def part_2() -> str:
    obstructions: list[Position] = [
        Position(map(int, x.split(",")[::-1]))  # row, col
        for x in open('year_2024_day_18.txt').read().splitlines()
    ]

    start_at = 1024

    initial = obstructions[:start_at]
    remaining = obstructions[start_at:]

    left, right = 0, len(obstructions) - 1
    last_working = start_at

    while left <= right:
        mid = (left + right) // 2
        current_obstructions = initial + remaining[: mid + 1]

        r = solve(71, 71, current_obstructions)

        if r != -1:
            left = mid + 1
            last_working = mid + start_at  # +start_at to get the correct index
        else:
            right = mid - 1

    row, col = obstructions[last_working + 1]
    return f"{col},{row}"

from collections import deque


def evolve(num: int) -> int:
    # equivalent to (num ^ (num * 64)) % 16777216
    num = (num ^ (num << 6)) & 0xFFFFFF

    # equivalent to (num ^ (num // 32)) % 16777216
    num = (num ^ (num >> 5)) & 0xFFFFFF

    # equivalent to (num ^ (num * 2048)) % 16777216
    num = (num ^ (num << 11)) & 0xFFFFFF
    return num


