            buyer = evolve(buyer)

        result += buyer

    return result


def part_2() -> int:
    buyers = map(int, open('year_2024_day_22.txt').read().splitlines())
    delta = {}

    for buyer in buyers:
        diff = deque(maxlen=4)
        seen = set()

        for _ in range(2000):
            new_buyer = evolve(buyer)

            initial_last_digit = buyer % 10
            next_last_digit = new_buyer % 10
            diff.append(next_last_digit - initial_last_digit)

            if len(diff) == 4:
                pattern = tuple(diff)
                if pattern not in seen:
                    seen.add(pattern)
                    delta[pattern] = delta.get(pattern, 0) + next_last_digit

            buyer = new_buyer

    return max(delta.values())

from enum import Enum


class RegistryDict(dict):
    def __getitem__(self, key):
        return super().__getitem__(key).value

    def __setitem__(self, key, value):
        if isinstance(value, int):
            super().__getitem__(key).value = value
        else:
            super().__setitem__(key, value)


class RegistryType(Enum):
    A = 4
    B = 5
    C = 6

    def __repr__(self) -> str:
        return f"{self.name}"

    def __str__(self) -> str:
        return self.__repr__()


class Registry:
    value: int

    def __init__(self, line: str) -> None:
        self.value = int(line)

    def __repr__(self) -> str:
        return f"Registry({self.value})"


class Opcode(Enum):
    ADV = 0  # division
    BXL = 1  # bitwise xor
    BST = 2  # modulo 8
    JNZ = 3  # jump
    BXC = 4  # bitwise xor
    OUT = 5  # modulo 8
    BDV = 6  # division
    CDV = 7  # division


def parse(file_name: str) -> tuple[RegistryDict, list[int]]:
    registries = RegistryDict()
    program = []

    with open('year_2024_day_17.txt') as file:
        for i, line in enumerate(file):
            if i < 3:
                registries[RegistryType(i + 4)] = Registry(line.split(":")[1].strip())

            if i == 4:
                program = list(map(int, line.split(":")[1].strip().split(",")))

    return registries, program


def combo(operand: int, registries: RegistryDict) -> int:
    if operand < 4:
        return operand

    return registries[RegistryType(operand)]


def evaluate(registries, program):
    out = []

    pointer = 0
    while pointer < len(program):
        opcode = Opcode(program[pointer])
        operand = program[pointer + 1]

        match opcode:
            case Opcode.ADV | Opcode.BDV | Opcode.CDV:
                target = None

                match opcode:
                    case Opcode.ADV:
                        target = RegistryType.A
                    case Opcode.BDV:
                        target = RegistryType.B
                    case Opcode.CDV:
                        target = RegistryType.C

                registries[target] = registries[RegistryType.A] >> combo(
                    operand, registries
                )  # same as // 2 ** operand

            case Opcode.BXL:
                registries[RegistryType.B] = registries[RegistryType.B] ^ operand

            case Opcode.BST:
                registries[RegistryType.B] = combo(operand, registries) % 8

            case Opcode.JNZ:
                if registries[RegistryType.A] != 0:
                    pointer = operand
                    continue

            case Opcode.BXC:
                registries[RegistryType.B] = (
                    registries[RegistryType.B] ^ registries[RegistryType.C]
                )

            case Opcode.OUT:
                out.append(combo(operand, registries) % 8)

        pointer += 2

    return out


def part_1() -> str:
    registries, program = parse("input.txt")

    return ",".join(map(str, evaluate(registries, program)))


def part_2() -> int:
    registries, program = parse("input.txt")

    candidates = [0]
    for length in range(1, len(program) + 1):
        out = []

        for num in candidates:
            # try all 3-bit combinations
            for offset in range(2**3):
                a = (2**3) * num + offset
                registries[RegistryType.A] = a

                if evaluate(registries, program) == program[-length:]:
                    out.append(a)

        candidates = out

    return min(candidates)

from typing import Any


def part_1() -> Any:
    disk_map = open('year_2024_day_9.txt').read().strip()
    blocks = []

    disk_id = 0
    for i in range(len(disk_map)):
        if i % 2 == 0:
            blocks.extend([disk_id] * int(disk_map[i]))

            disk_id += 1
        else:
            blocks.extend(["."] * int(disk_map[i]))

    for i in (i for i, x in enumerate(blocks) if x == "."):
        while blocks[-1] == ".":
            blocks.pop()

        if len(blocks) <= i:
            break

        blocks[i] = blocks.pop()

    return sum(i * int(x) for i, x in enumerate(blocks) if x != ".")


def part_2() -> Any:
    disk_map = open('year_2024_day_9.txt').read().strip()
    free_space = []
    files = {}

    disk_id = 0
    position = 0

    for i in range(len(disk_map)):
        size = int(disk_map[i])
        if i % 2 == 0:
            files[disk_id] = (position, size)

            disk_id += 1
        else:
            if size > 0:
                free_space.append((position, size))

        position += size

    for disk_id in range(len(files) - 1, -1, -1):
        pos, size = files[disk_id]
        found = None

        for idx, (start, length) in enumerate(free_space):
            if start >= pos:
                free_space = free_space[:idx]
                found = None
                break

            if size <= length:
                found = (idx, start, length)
                break

        if found:
            idx, start, length = found
            files[disk_id] = (start, size)

            if size == length:
                free_space.pop(idx)
            else:
                free_space[idx] = (start + size, length - size)

    return sum(
        disk_id * x
        for disk_id, (pos, size) in files.items()
        for x in range(pos, pos + size)
    )

import sys
from collections import defaultdict


class Heap:

    def __init__(self):
        self.data = []

    def insert(self, score, item):
        from heapq import heappush
        heappush(self.data, (score, item))

    def pop_min(self):
        from heapq import heappop
        score, item = self.data[0]
        heappop(self.data)
        return item

    def __bool__(self):
        return bool(self.data)


def parse_data(file_name):
    with open('year_2021_day_15.txt', 'r') as f:
        content = f.readlines()
    grid = []
    for line in content:
        row = []
        for cel in line.strip():
            row.append(int(cel))
        grid.append(row)
    return grid


def create_graph(grid):
    """ Create graph from from list of lists """
    maze = defaultdict(dict)
    x_size = len(grid)
    y_size = len(grid[0])
    for x in range(x_size):
        for y in range(y_size):
            maze[(x, y)] = neighbours(grid, x_size, y_size, x, y)
    return maze


def neighbours(grid, x_size, y_size, x, y):
    raw_neighbours = [
        (x - 1, y),
        (x, y - 1),
        (x, y + 1),
        (x + 1, y),
    ]
    real_neighbours = {}
    for i in raw_neighbours:
        if i[0] < 0 or i[1] < 0:
            continue
        if i[0] >= x_size or i[1] >= y_size:
            continue
        real_neighbours[i] = grid[i[0]][i[1]]
    return real_neighbours


# PART 1 - Dijkstra algorithm
def part_one(grid, target_node):
    maze = create_graph(grid)
    start_node = (0, 0)
    unvisited_nodes = Heap()
    unvisited_nodes.insert(0, start_node)
    shortest_path = {}
    previous_nodes = {}

    max_value = sys.maxsize
    for node in maze.keys():
        shortest_path[node] = max_value
    # initialize the starting node value with 0
    shortest_path[start_node] = 0

    # visit all nodes
    while unvisited_nodes:
        current_min_node = unvisited_nodes.pop_min()

        # current node's neighbors and updating their distances
        neighbors = maze[current_min_node]
        for neighbor in neighbors:
            tentative_value = (
                shortest_path[current_min_node] +
                maze[current_min_node][neighbor]
                )
            if tentative_value < shortest_path[neighbor]:
                shortest_path[neighbor] = tentative_value
                # best path to the current node
                previous_nodes[neighbor] = current_min_node
                unvisited_nodes.insert(tentative_value, neighbor)

    return shortest_path[target_node]


# PART two - extending map
def part_two(grid, target_node):
    # extending grid 5x to the side
    wide_grid = []
    for line in grid:
        new_line = []
        for i in range(5):
            for j in line:
                x = j + i
                if x > 9:
                    new_line.append(x - 9)
                else:
                    new_line.append(x)
        wide_grid.append(new_line)
    # make grid 5x longer
    long_grid = []
    for i in range(5):
        for line in wide_grid:
            new_line = []
            for j in line:
                x = j + i
                if x > 9:
                    new_line.append(x - 9)
                else:
                    new_line.append(x)
            long_grid.append(new_line)

    total_risk = part_one(long_grid, target_node)
    return total_risk


def main(file_name):
    grid = parse_data(file_name)
    part_1 = part_one(grid, (99, 99))
    part_2 = part_two(grid, (499, 499))
    return part_1, part_2


if __name__ == '__main__':
    part_1, part_2 = main("15_input.txt")

    print(f"Part one: {part_1}")
    print(f"Part two: {part_2}")

