def get_heights(lines, top):
    width = len(lines[0])
    heights = []

    for col in range(width):
        height = 0
        if top:
            for row in range(len(lines)):
                if lines[row][col] == "#":
                    height = row + 1
        else:
            for row in range(len(lines) - 1, -1, -1):
                if lines[row][col] == "#":
                    height = len(lines) - row
        heights.append(height)

    return heights


