    for i in range(len(values[0])):
        mcv = most_common([int(bit[i]) for bit in values])
        if ox:
            values = [value for value in values if int(value[i]) == mcv]
        else:
            values = [value for value in values if int(value[i]) != mcv]

        if len(values) == 1:
            return int(values[0], 2)

    return int(values[0], 2)


