def slide_sweep(depths: list) -> str:
    increases = 0
    if len(depths) > 3:
        previous_depth = sum(depths[:3])
        for i in range(1, len(depths)):
            if i < len(depths) - 2:
                if sum(depths[i:i+3]) > previous_depth:
                    increases += 1
                previous_depth = sum(depths[i:i+3])

    return increases


