    traversed_locations = [[False] * (len(tubes[0])) for _ in range(len(tubes))]

    size = []

    for y in range(len(tubes)):
        for x in range(len(tubes[y])):
            lowpoint = True
            if y > 0:
                if tubes[y - 1][x] <= tubes[y][x]:
                    lowpoint = False

            if y < len(tubes) - 1:
                if tubes[y + 1][x] <= tubes[y][x]:
