def calc(log, values, mode):
    from grid import Grid, Point
    grid = []
    moves = None
    for cur in values:
        if len(cur) == 0:
            moves = []
        elif moves is None:
            grid.append(cur)
        else:
            moves.append(cur)

    if mode == 2:
        for i in range(len(grid)):
            temp = ""
            for cur in grid[i]:
                if cur in {"#", "."}:
                    temp += cur + cur
                elif cur == "O":
                    temp += "[]"
                elif cur == "@":
                    temp += "@."
                else:
                    raise Exception()
            grid[i] = temp

    grid = Grid.from_text(grid)
    for xy in grid.xy_range():
        if grid[xy] == "@":
            robot = Point(xy)
            grid[xy] = "."
            break

    for row in moves:
        for cur in row:
            x, y, up_down = {"^": (0, -1, True), "v": (0, 1, True), "<": (-1, 0, False), ">": (1, 0, False)}[cur]
            d = Point(x, y)
            to_move = []
            empty = 0
            if mode == 2 and up_down:
                temp = robot + Point(0, 0)
                row = [temp]
                while True:
                    all_empty = True
                    for cur in row:
                        if grid[cur + d] != ".":
                            all_empty = False
                    if all_empty:
                        empty += 1
                        break

                    any_wall = False
                    for cur in row:
                        if grid[cur + d] == "#":
                            any_wall = True
                    if any_wall:
                        break

                    hit = set()
                    for cur in row:
                        if grid[cur + d] == "[":
                            hit.add(cur + d)
                            hit.add(cur + d + Point(1, 0))
                        elif grid[cur + d] == "]":
                            hit.add(cur + d)
                            hit.add(cur + d - Point(1, 0))
                    row = []
                    for cur in hit:
                        row.append(cur)
                        to_move.append((cur, grid[cur]))
                    temp += d

            else:
                temp = robot + d
                while True:
                    if grid[temp] == ".":
                        empty += 1
                        break
                    elif grid[temp] == "O":
                        to_move.append((temp, grid[temp]))
                    elif grid[temp] in {"[", "]"}:
                        to_move.append((temp, grid[temp]))
                    else:
                        break
                    temp += d

            if empty > 0:
                robot += d
                for cur, _ in to_move:
                    grid[cur] = "."
                for cur, val in to_move:
                    grid[cur + d] = val

