def verify(line: str, missing: str = "") -> Tuple[str, str]:
    start, line = line[0], line[1:]
    end = ENDS[start]
    while line:
        if line[0] in ENDS.values():
            if line[0] != end:
                raise Corrupted(end, line[0])
            return line[1:], missing
        elif line[0] in STARTERS:
            line, missing = verify(line)
    missing += end
    return "", missing


